@startuml
skinparam classAttributeIconSize 0

class Game {
}

interface PropFactory <<I>> {
    + create(int x,int y):AbstractProp
}

abstract class AbstractProp <<A>> {
    # propkind

    - AbstractProp(int locationX, int locationY, 
                   int speedX, int speedy) : void
    + getpropKind() :int
}


BloodTool --|> BloodProp  
BombProp --|> BombProp   
FireTool --|> FireProp  

Game ..> PropFactory 

PropFactory <|-- BloodFactory    
PropFactory <|-- BombFactory     
PropFactory <|-- FireFactory     

BloodFactory --> "create" BloodProp      
BombFactory --> "create" BombProp       
FireFactory --> "create" FireProp       



@enduml
